@push('scripts')<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.4/dist/chart.umd.min.js"></script><script>const c=@json($charts),palette=['#4f46e5','#06b6d4','#f59e0b','#10b981','#ef4444','#ec4899','#2563eb'];const common={responsive:true,animation:{duration:1500,easing:'easeOutQuart'},plugins:{tooltip:{enabled:true,displayColors:true}}};new Chart($('#pieChart'),{type:'doughnut',data:{labels:c.labels,datasets:[{data:c.actual,backgroundColor:palette,borderWidth:3,borderColor:'#fff'}]},options:{...common,cutout:'62%'}});new Chart($('#candleChart'),{type:'bar',data:{labels:c.labels,datasets:[{label:'Target',data:c.target,backgroundColor:'#c7d2fe',borderColor:'#4f46e5',borderWidth:2,borderRadius:8},{label:'Actual',data:c.actual,backgroundColor:'#5eead4',borderColor:'#0f766e',borderWidth:2,borderRadius:8}]},options:{...common,scales:{y:{beginAtZero:true}}}});new Chart($('#waveChart'),{type:'line',data:{labels:c.labels,datasets:[{label:'Target wave',data:c.target,borderColor:'#4f46e5',backgroundColor:'rgba(79,70,229,.12)',fill:true,tension:.45},{label:'Actual wave',data:c.actual,borderColor:'#0f766e',backgroundColor:'rgba(15,118,110,.12)',fill:true,tension:.45}]},options:{...common,scales:{y:{beginAtZero:true}}}});new Chart($('#radarChart'),{type:'radar',data:{labels:c.labels,datasets:[{label:'Achievement %',data:c.achievement,backgroundColor:'rgba(79,70,229,.2)',borderColor:'#4f46e5',pointBackgroundColor:palette}]},options:{...common,scales:{r:{beginAtZero:true,suggestedMax:100}}}});$('.chart-tab').on('click',function(){$('.chart-tab').removeClass('active');$('.chart-pane').removeClass('active');$(this).addClass('active');$('#'+$(this).data('pane')).addClass('active');});@if($rows->count())$('#reportTable').DataTable({pageLength:25,order:[[5,'desc']]});@endif</script>@endpush
